const mono = { fontFamily: 'IBM Plex Mono, monospace' } as const;

// ─── InlineEdit ───────────────────────────────────────────────────────────────

function InlineEdit({ value, onSave }: { value: string; onSave: (v: string) => void }) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value);

  const commit = () => {
    const trimmed = draft.trim();
    if (trimmed && trimmed !== value) onSave(trimmed);
    else setDraft(value);
    setEditing(false);
  };

  if (editing) {
    return (
      <input
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onBlur={commit}
        onKeyDown={(e) => {
          if (e.key === 'Enter') commit();
          if (e.key === 'Escape') { setDraft(value); setEditing(false); }
        }}
        autoFocus
        style={{
          background: 'var(--bg-surface)',
          border: '1px solid var(--phosphor-dim)',
          color: 'var(--text-primary)',
          ...mono,
          fontSize: 13,
          fontWeight: 500,
          padding: '1px 5px',
          outline: 'none',
          width: '100%',
        }}
      />
    );
  }

  return (
    <span
      onClick={() => { setDraft(value); setEditing(true); }}
      title="Click to rename"
      style={{
        ...mono,
        fontSize: 13,
        fontWeight: 500,
        color: 'var(--text-primary)',
        cursor: 'text',
        display: 'block',
        overflow: 'hidden',
        textOverflow: 'ellipsis',
        whiteSpace: 'nowrap',
        borderBottom: '1px dashed transparent',
      }}
      onMouseEnter={(e) => { (e.currentTarget as HTMLElement).style.borderBottomColor = 'var(--border-accent)'; }}
      onMouseLeave={(e) => { (e.currentTarget as HTMLElement).style.borderBottomColor = 'transparent'; }}
    >
      {value}
    </span>
  );
}

// ─── PortList ─────────────────────────────────────────────────────────────────

function PortList({
  nodeId,
  nodeType,
  ports,
  counts,
}: {
  nodeId: string;
  nodeType: ComponentDef['type'];
  ports: PortDef[];
  counts: Record<string, number>;
}) {
  const togglePort = useDiagramStore((s) => s.togglePort);
  const setPortCount = useDiagramStore((s) => s.setPortCount);
  const boardMode = nodeType === 'board';
  const gridTemplateColumns = boardMode
    ? '28px 14px minmax(0,1fr) 58px 44px'
    : '28px 14px 1fr 50px';

  return (
    <div style={{ flex: 1, overflowY: 'auto', ...mono }}>
      {/* column headers */}
      <div
        style={{
          display: 'grid',
          gridTemplateColumns,
          gap: 0,
          padding: '3px 12px',
          borderBottom: '1px solid var(--border)',
          fontSize: 9,
          letterSpacing: '0.09em',
          color: 'var(--text-muted)',
        }}
      >
        <span>USE</span>
        <span />
        <span>PORT</span>
        {boardMode && <span style={{ textAlign: 'center' }}>QTY</span>}
        <span style={{ textAlign: 'right' }}>ID</span>
      </div>

      {ports.map((port) => {
        const count = counts[port.id] ?? 0;
        const active = count > 0;
        return (
          <div
            key={port.id}
            onClick={() => togglePort(nodeId, port.id)}
            style={{
              display: 'grid',
              gridTemplateColumns,
              gap: 0,
              padding: '0 12px',
              height: 26,
              alignItems: 'center',
              borderBottom: '1px solid var(--border)',
              background: active ? 'rgba(0,230,118,0.05)' : 'transparent',
              cursor: 'pointer',
            }}
          >
            <input
              type="checkbox"
              checked={active}
              readOnly
              onClick={(e) => e.stopPropagation()}
              onChange={() => togglePort(nodeId, port.id)}
              style={{
                accentColor: 'var(--phosphor)',
                cursor: 'pointer',
                margin: 0,
                pointerEvents: 'none',
              }}
            />
            <span
              style={{
                width: 8,
                height: 8,
                borderRadius: '50%',
                background: ROLE_COLOR[port.role] ?? '#888',
                display: 'inline-block',
                opacity: active ? 1 : 0.3,
              }}
            />
            <span
              style={{
                fontSize: 11,
                color: active ? 'var(--text-primary)' : 'var(--text-muted)',
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
              }}
              >
                {port.label}
              </span>
            {boardMode && (
              <div
                onClick={(e) => e.stopPropagation()}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 3,
                }}
              >
                <button
                  onClick={() => setPortCount(nodeId, port.id, count - 1)}
                  disabled={!active}
                  style={{
                    width: 16,
                    height: 16,
                    background: 'var(--bg-panel)',
                    border: '1px solid var(--border)',
                    color: active ? 'var(--text-secondary)' : 'var(--text-muted)',
                    cursor: active ? 'pointer' : 'not-allowed',
                    fontSize: 10,
                    lineHeight: 1,
                    padding: 0,
                  }}
                  title={`Remove one mapping from ${port.id}`}
                >
                  -
                </button>
                <span
                  style={{
                    minWidth: 10,
                    fontSize: 10,
                    color: active ? 'var(--phosphor)' : 'var(--text-muted)',
                    textAlign: 'center',
                  }}
                >
                  {count}
                </span>
                <button
                  onClick={() => setPortCount(nodeId, port.id, active ? count + 1 : 1)}
                  style={{
                    width: 16,
                    height: 16,
                    background: 'var(--bg-panel)',
                    border: '1px solid var(--border)',
                    color: 'var(--text-secondary)',
                    cursor: 'pointer',
                    fontSize: 10,
                    lineHeight: 1,
                    padding: 0,
                  }}
                  title={`Add one mapping to ${port.id}`}
                >
                  +
                </button>
              </div>
            )}
            <span
              style={{
                fontSize: 9,
                fontWeight: 600,
                color: ROLE_COLOR[port.role] ?? 'var(--text-secondary)',
                textAlign: 'right',
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
              }}
              title={port.id}
            >
              {port.id}
            </span>
          </div>
