                background: ROLE_COLOR[port.role] ?? '#888',
                display: 'inline-block',
                opacity: active ? 1 : 0.3,
              }}
            />
            <span
              style={{
                fontSize: 11,
                color: active ? 'var(--text-primary)' : 'var(--text-muted)',
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
              }}
              >
                {port.label}
              </span>
            {boardMode && (
              <div
                onClick={(e) => e.stopPropagation()}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 3,
                }}
              >
                <button
                  onClick={() => setPortCount(nodeId, port.id, count - 1)}
                  disabled={!active}
                  style={{
                    width: 16,
                    height: 16,
                    background: 'var(--bg-panel)',
                    border: '1px solid var(--border)',
                    color: active ? 'var(--text-secondary)' : 'var(--text-muted)',
                    cursor: active ? 'pointer' : 'not-allowed',
                    fontSize: 10,
                    lineHeight: 1,
                    padding: 0,
                  }}
                  title={`Remove one mapping from ${port.id}`}
                >
                  -
                </button>
                <span
                  style={{
                    minWidth: 10,
                    fontSize: 10,
                    color: active ? 'var(--phosphor)' : 'var(--text-muted)',
                    textAlign: 'center',
                  }}
                >
                  {count}
                </span>
                <button
                  onClick={() => setPortCount(nodeId, port.id, active ? count + 1 : 1)}
                  style={{
                    width: 16,
                    height: 16,
                    background: 'var(--bg-panel)',
                    border: '1px solid var(--border)',
                    color: 'var(--text-secondary)',
                    cursor: 'pointer',
                    fontSize: 10,
                    lineHeight: 1,
                    padding: 0,
                  }}
                  title={`Add one mapping to ${port.id}`}
                >
                  +
                </button>
              </div>
            )}
            <span
              style={{
                fontSize: 9,
                fontWeight: 600,
                color: ROLE_COLOR[port.role] ?? 'var(--text-secondary)',
                textAlign: 'right',
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
              }}
              title={port.id}
            >
              {port.id}
            </span>
          </div>
        );
      })}
    </div>
  );
}

function ConnectionsSection({
  nodeId,
  defs,
}: {
  nodeId: string;
  defs: ComponentDef[];
}) {
  const nodes = useDiagramStore((s) => s.nodes);
  const edges = useDiagramStore((s) => s.edges);

  const myNode = nodes.find((n) => n.instanceId === nodeId);
  const myTicks = myNode ? getTotalAssignedPorts(myNode) : 0;
  const myType = myNode ? defs.find((def) => def.id === myNode.defId)?.type : undefined;
  const connectedEdges = edges.filter(
    (e) => e.fromNode === nodeId || e.toNode === nodeId
  );

  if (connectedEdges.length === 0) return null;

  return (
    <div
      style={{
        borderTop: '1px solid var(--border)',
        padding: '8px 12px',
        ...mono,
        flexShrink: 0,
      }}
    >
      <div style={{ fontSize: 9, letterSpacing: '0.1em', color: 'var(--text-muted)', marginBottom: 6 }}>
        CONNECTIONS
      </div>
      {connectedEdges.map((edge) => {
        const otherId = edge.fromNode === nodeId ? edge.toNode : edge.fromNode;
        const other = nodes.find((n) => n.instanceId === otherId);
        if (!other) return null;

        const assignment = analyzeEdgeAssignment(edge.id, nodes, edges, defs);
        if (!assignment) return null;

        const otherType = defs.find((def) => def.id === other.defId)?.type;
        const otherTicks = otherType === 'board'
          ? assignment.assignedBoardPorts.length
          : assignment.sensorPorts.length;
        const bothZero = assignment.sensorPorts.length === 0 && assignment.assignedBoardPorts.length === 0;
        const mismatch = !bothZero && assignment.edgeMismatch;
        const otherTickLabel = otherType === 'board' ? 'assigned slot' : 'active port';
        const myLabel = myType === 'board' ? 'assigned' : 'active';
        const mapping = formatPortMapping(assignment);

        return (
          <div key={edge.id} style={{ marginBottom: 5 }}>
            <div style={{ fontSize: 11, color: 'var(--text-primary)', display: 'flex', gap: 6, alignItems: 'center' }}>
              <span
                style={{
                  width: 6,
                  height: 6,
                  borderRadius: '50%',
                  background: bothZero ? 'var(--text-muted)' : mismatch ? '#f59e0b' : 'var(--phosphor)',
                  display: 'inline-block',
                  flexShrink: 0,
                }}
              />
              <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                {other.label}
              </span>
              <span style={{ color: 'var(--text-muted)', fontSize: 10, flexShrink: 0 }}>
                {otherTicks} {otherTickLabel}{otherTicks !== 1 ? 's' : ''}
              </span>
            </div>
            <div style={{ fontSize: 10, color: 'var(--text-muted)', marginTop: 3 }}>
              {mapping}
            </div>
            {mismatch && (
              <div style={{ fontSize: 10, color: 'var(--red)', marginTop: 3, lineHeight: 1.4 }}>
                {assignment.edgeMissingBoardSlots
                  ? myType === 'board'
                    ? `${other.label} needs ${assignment.sensorPorts.length} active port${assignment.sensorPorts.length !== 1 ? 's' : ''}, but this connection only has ${assignment.assignedBoardPorts.length} assigned slot${assignment.assignedBoardPorts.length !== 1 ? 's' : ''}.`
                    : `Connected to ${other.label}: you have ${myTicks} ${myLabel}, but this connection only has ${assignment.assignedBoardPorts.length} assigned slot${assignment.assignedBoardPorts.length !== 1 ? 's' : ''}.`
                  : `${mapping} contains ${assignment.edgeIncompatibleSlots} invalid mapping${assignment.edgeIncompatibleSlots !== 1 ? 's' : ''}.`}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

function ConfigurePanel({
  effectivePorts,
  onApply,
  onCancel,
}: {
  effectivePorts: PortDef[];
  onApply: (ports: PortDef[]) => void;
  onCancel: () => void;
}) {
  const [drafts, setDrafts] = useState<PortDraft[]>(() =>
    effectivePorts.map((p) => ({ ...p, _key: nextPk() }))
  );

  const addPort = () => setDrafts((prev) => [...prev, { id: '', label: '', role: 'digital', _key: nextPk() }]);
  const removePort = (key: number) => setDrafts((prev) => prev.filter((p) => p._key !== key));
  const updatePort = (key: number, patch: Partial<PortDef>) =>
    setDrafts((prev) => prev.map((p) => (p._key === key ? { ...p, ...patch } : p)));

  const valid = drafts.length > 0 && drafts.every((p) => p.id.trim() && p.label.trim());

  return (
    <>
      <div className="flex-1 overflow-y-auto" style={{ padding: '8px 10px', ...mono }}>
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: '56px 1fr 76px 22px',
            gap: 3,
            marginBottom: 5,
            fontSize: 9,
            letterSpacing: '0.08em',
            color: 'var(--text-muted)',
          }}
        >
          <span>ID</span><span>LABEL</span><span>ROLE</span><span />
        </div>

        {drafts.map((port) => (
          <div
            key={port._key}
            style={{ display: 'grid', gridTemplateColumns: '56px 1fr 76px 22px', gap: 3, marginBottom: 3 }}
          >
            <input
              value={port.id}
              onChange={(e) => updatePort(port._key, { id: e.target.value })}
              placeholder="D3"
              style={cfgInput}
            />
            <input
              value={port.label}
              onChange={(e) => updatePort(port._key, { label: e.target.value })}
              placeholder="D3 (~)"
              style={cfgInput}
            />
            <select
              value={port.role}
              onChange={(e) => updatePort(port._key, { role: e.target.value as PortRole })}
              style={{ ...cfgInput, paddingRight: 2 }}
            >
              {PORT_ROLES.map((r) => <option key={r} value={r}>{r}</option>)}
            </select>
            <button
              onClick={() => removePort(port._key)}
              disabled={drafts.length === 1}
              style={{
                background: 'none',
                border: 'none',
                color: drafts.length === 1 ? 'var(--text-muted)' : 'var(--red)',
                cursor: drafts.length === 1 ? 'not-allowed' : 'pointer',
                fontSize: 12,
                lineHeight: 1,
                padding: 0,
              }}
            >
              ✕
            </button>
          </div>
        ))}

        <button
          onClick={addPort}
          style={{
            marginTop: 6,
            width: '100%',
            background: 'none',
            border: '1px solid var(--border)',
            color: 'var(--text-secondary)',
            ...mono,
            fontSize: 10,
            padding: '4px 0',
            cursor: 'pointer',
            letterSpacing: '0.06em',
          }}
        >
          + ADD PORT
        </button>
      </div>

      <div
        className="flex gap-2 border-t"
        style={{ borderColor: 'var(--border)', padding: '8px 10px', flexShrink: 0 }}
      >
        <button
          onClick={onCancel}
          style={{
            flex: 1,
            background: 'none',
            border: '1px solid var(--border)',
            color: 'var(--text-muted)',
            ...mono,
            fontSize: 10,
            padding: '5px 0',
            cursor: 'pointer',
            letterSpacing: '0.06em',
          }}
        >
          CANCEL
        </button>
        <button
          onClick={() =>
            onApply(drafts.map((draft) => ({
              id: draft.id,
              label: draft.label,
              role: draft.role,
            })))
          }
          disabled={!valid}
          style={{
            flex: 2,
            background: valid ? 'var(--phosphor-mute)' : 'transparent',
            border: `1px solid ${valid ? 'var(--phosphor-dim)' : 'var(--border)'}`,
            color: valid ? 'var(--phosphor)' : 'var(--text-muted)',
            ...mono,
            fontSize: 10,
            fontWeight: 600,
            padding: '5px 0',
            cursor: valid ? 'pointer' : 'not-allowed',
            letterSpacing: '0.06em',
          }}
        >
          APPLY
        </button>
      </div>
    </>
  );
}

function Inspector() {
  const store = useDiagramStore();
  const allDefs = [...ALL_DEFS, ...store.customDefs];

  const node = store.nodes.find((n) => n.instanceId === store.selectedId);
  const def = node ? allDefs.find((d) => d.id === node.defId) : undefined;
  const effectivePorts = node && def ? getEffectivePorts(node, allDefs) : [];

  const [configuringForId, setConfiguringForId] = useState<string | null>(null);

  if (!node || !def) {
    return (
      <aside
        className="flex items-center justify-center border-l"
        style={{ width: 280, flexShrink: 0, background: 'var(--bg-panel)', borderColor: 'var(--border)' }}
      >
        <span style={{ ...mono, fontSize: 11, color: 'var(--text-muted)' }}>
          select a component
        </span>
      </aside>
    );
  }

  const activeTicks = getTotalAssignedPorts(node);
  const configuring = configuringForId === node.instanceId;
  const portCounts = Object.fromEntries(
    effectivePorts.map((port) => [port.id, getPortCount(node, port.id)])
  );
  const defaultPorts = def.ports;

  return (
    <aside
      className="flex flex-col border-l"
      style={{ width: 280, flexShrink: 0, background: 'var(--bg-panel)', borderColor: 'var(--border)' }}
    >
      {/* header */}
      <div
        className="border-b"
        style={{ borderColor: 'var(--border)', padding: '8px 12px', flexShrink: 0 }}
      >
        {configuring ? (
          <div style={mono}>
            <div style={{ fontSize: 9, letterSpacing: '0.1em', color: 'var(--amber)', marginBottom: 3 }}>
              CONFIGURE PORTS
            </div>
            <div style={{ fontSize: 12, color: 'var(--text-primary)', fontWeight: 500 }}>{node.label}</div>
          </div>
        ) : (
          <div style={mono}>
            <div style={{ fontSize: 9, letterSpacing: '0.1em', color: 'var(--phosphor)', marginBottom: 3 }}>
              INSPECTOR
            </div>
            <InlineEdit
              value={node.label}
              onSave={(label) => store.renameNode(node.instanceId, label)}
            />
            <div style={{ fontSize: 10, color: 'var(--text-muted)', marginTop: 3 }}>
              {def.type}
              {def.category ? ` · ${def.category}` : ''}
              {' · '}{effectivePorts.length} ports
              {' · '}{activeTicks} {def.type === 'board' ? 'assigned' : 'active'}
              {node.portsOverride && (
                <span style={{ color: 'var(--amber)', marginLeft: 4 }}>★ custom</span>
              )}
            </div>
          </div>
        )}
      </div>

      {/* body */}
      {configuring ? (
          <ConfigurePanel
            effectivePorts={effectivePorts}
            onApply={(ports) => {
              store.setNodePortsOverride(
                node.instanceId,
                ports,
                ports.map((port) => port.id)
              );
              setConfiguringForId(null);
            }}
          onCancel={() => setConfiguringForId(null)}
        />
      ) : (
        <>
          <PortList
            nodeId={node.instanceId}
            nodeType={def.type}
            ports={effectivePorts}
            counts={portCounts}
          />

          <ConnectionsSection nodeId={node.instanceId} defs={allDefs} />

          {/* footer */}
          <div
            className="border-t"
            style={{ borderColor: 'var(--border)', padding: '8px 12px', flexShrink: 0 }}
          >
            <button
              onClick={() => setConfiguringForId(node.instanceId)}
              style={{
                width: '100%',
                background: 'none',
                border: '1px solid var(--border)',
                color: 'var(--text-secondary)',
                ...mono,
                fontSize: 11,
                letterSpacing: '0.06em',
                padding: '5px 0',
                cursor: 'pointer',
              }}
            >
              CONFIGURE PORTS
            </button>
            {node.portsOverride && (
              <button
                onClick={() => store.setNodePortsOverride(
                  node.instanceId,
                  undefined,
                  defaultPorts.map((port) => port.id)
                )}
                style={{
                  width: '100%',
                  background: 'none',
                  border: 'none',
                  color: 'var(--text-muted)',
                  ...mono,
                  fontSize: 10,
                  padding: '4px 0',
                  cursor: 'pointer',
                  letterSpacing: '0.04em',
                  marginTop: 4,
                }}
              >
                reset to default ports
              </button>
            )}
          </div>
        </>
      )}
    </aside>
  );
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useDiagramStore } from '../../store/diagram';
import {
  buildProjectFileName,
  downloadFile,
  exportArduinoPromptMarkdown,
  exportProjectFile,
  exportArduinoStub,
  exportJSON,
  exportShareURL,
  parseProjectFileContent,
} from '../../lib/export';
import { saveDiagram } from '../../lib/storage';

interface Props {
  theme: 'dark' | 'light';
  onToggleTheme: () => void;
}

const mono: React.CSSProperties = {
  fontFamily: 'IBM Plex Mono, monospace',
  letterSpacing: '0.06em',
