interface Props {
  theme: 'dark' | 'light';
  onToggleTheme: () => void;
}

function Btn({
  label,
  title,
  onClick,
  disabled,
  accent,
}: {
  label: string;
  title?: string;
  onClick: () => void;
  disabled?: boolean;
  accent?: boolean;
}) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      title={title}
      style={{
        ...mono,
        fontSize: 11,
        color: disabled
          ? 'var(--text-muted)'
          : accent
            ? 'var(--phosphor)'
            : 'var(--text-secondary)',
        background: accent ? 'var(--phosphor-mute)' : 'none',
        border: accent ? '1px solid var(--phosphor-dim)' : 'none',
        padding: accent ? '3px 10px' : '0',
        cursor: disabled ? 'not-allowed' : 'pointer',
        flexShrink: 0,
      }}
    >
      {label}
    </button>
  );
}

function Sep() {
  return (
    <span
      style={{
        width: 1,
        height: 16,
        background: 'var(--border)',
        display: 'inline-block',
        flexShrink: 0,
      }}
    />
  );
}

